*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background: transparent;
  overflow: hidden;
  font-family: "Figtree", Inter, system-ui, sans-serif;
}

#nav {
  display: flex;
  align-items: center;
  height: 56px;
  padding: 0 12px;
  width: 100%;
  background: #05042E;
  gap: 0;
}

.logo {
  color: #fff;
  font-size: 14px;
  font-weight: 700;
  letter-spacing: -0.02em;
  padding: 0 8px;
  flex-shrink: 0;
}

.div {
  width: 0.5px;
  background: rgba(255, 255, 255, 0.12);
  height: 22px;
  margin: 0 8px;
  flex-shrink: 0;
}

.grp {
  display: flex;
  align-items: center;
  gap: 1px;
}

.btn {
  background: transparent;
  border: none;
  color: rgba(255, 255, 255, 0.5);
  font-size: 12.5px;
  font-family: inherit;
  font-weight: 400;
  padding: 5px 10px;
  border-radius: 5px;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
  white-space: nowrap;
}

.btn:hover {
  background: rgba(255, 255, 255, 0.08);
  color: #fff;
}

.btn.active {
  background: rgba(255, 255, 255, 0.13);
  color: #fff;
  font-weight: 600;
}

.spacer {
  flex: 1;
}

.user {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.avatar {
  width: 26px;
  height: 26px;
  border-radius: 50%;
  background: #469BC0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 9px;
  font-weight: 700;
  color: #fff;
}

#username {
  color: rgba(255, 255, 255, 0.55);
  font-size: 12.5px;
  white-space: nowrap;
}

.signout-link {
  font-family: inherit;
  font-size: 12px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.7);
  background: transparent;
  border: none;
  cursor: pointer;
  margin-left: 12px;
  padding: 4px 8px;
  border-radius: 6px;
}

.signout-link:hover {
  color: #fff;
  background: rgba(255, 255, 255, 0.1);
}

