appsmith.onReady(function () {
  init();
});
appsmith.onModelChange(function () {
  init();
});
function init() {
  var model = appsmith.model;
  var activePage = model && model.activePage ? model.activePage : '';
  document.querySelectorAll('.btn').forEach(function (btn) {
    btn.className = btn.getAttribute('data-page') === activePage ? 'btn active' : 'btn';
  });
  var userName = model && model.userName ? model.userName : '';
  if (userName) {
    document.getElementById('username').textContent = userName.split(' ')[0];
    var parts = userName.trim().split(' ');
    var initials = parts.length >= 2 ? parts[0][0].toUpperCase() + parts[parts.length - 1][0].toUpperCase() : parts[0].substring(0, 2).toUpperCase();
    document.getElementById('initials').textContent = initials;
  }
}
window.go = function (eventName) {
  appsmith.triggerEvent(eventName);
};
// --- Auto-logout after 20 minutes of inactivity ---
var IDLE_LIMIT_MS = 20 * 60 * 1000; // 20 minutes
var idleTimer = null;
function performAutoLogout() {
  if (typeof appsmith === 'undefined' || !appsmith.store.userEmail) return; // already signed out, nothing to do
  appsmith.triggerEvent('onAutoLogout');
}
function resetIdleTimer() {
  if (idleTimer) clearTimeout(idleTimer);
  idleTimer = setTimeout(performAutoLogout, IDLE_LIMIT_MS);
}
function startIdleWatch() {
  ['mousemove', 'mousedown', 'keydown', 'scroll', 'touchstart', 'click'].forEach(function (evt) {
    document.addEventListener(evt, resetIdleTimer, {
      passive: true
    });
  });
  resetIdleTimer();
}
startIdleWatch();
function initSignOutLink() {
  var btn = document.getElementById('signout_link');
  if (btn && !btn.dataset.bound) {
    btn.dataset.bound = 'true';
    btn.addEventListener('click', function () {
      appsmith.triggerEvent('onSignOut');
    });
  }
}
appsmith.onReady(function () {
  initSignOutLink();
});
appsmith.onModelChange(function () {
  initSignOutLink();
});

